package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    void testGetHeaderCommentsWhenNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // headerComments is null in DEFAULT, verify returns null
        String[] result = format.getHeaderComments();
        assertNull(result);
    }

    @Test
    void testGetHeaderCommentsReturnsClone() throws Exception {
        // Use reflection to create CSVFormat instance with headerComments set
        CSVFormat format = CSVFormat.DEFAULT;

        Field headerCommentsField = CSVFormat.class.getDeclaredField("headerComments");
        headerCommentsField.setAccessible(true);
        String[] comments = new String[] {"comment1", "comment2"};
        headerCommentsField.set(format, comments);

        String[] result = format.getHeaderComments();

        assertNotNull(result);
        assertArrayEquals(comments, result);
        assertNotSame(comments, result);

        // Modify returned array and verify original not affected
        result[0] = "modified";
        String[] original = (String[]) headerCommentsField.get(format);
        assertEquals("comment1", original[0]);
    }
}
